import React, { useState, useEffect } from 'react';
import Editor from '@monaco-editor/react';
import Sidebar from '../components/common/Sidebar';
import AnalysisPanel from '../components/workspace/AnalysisPanel';
import api from '../utils/api';

const LANGS = [
  {v:'python',l:'Python'},{v:'javascript',l:'JavaScript'},{v:'typescript',l:'TypeScript'},
  {v:'cpp',l:'C++'},{v:'c',l:'C'},{v:'java',l:'Java'},{v:'go',l:'Go'},{v:'rust',l:'Rust'},{v:'ruby',l:'Ruby'}
];
const STARTERS = {
  python:'# Write your solution here\ndef solve():\n    n = int(input())\n    print(n)\n\nsolve()',
  javascript:'// Write your solution here\nfunction solve() {\n  // your code\n}\nsolve();',
  cpp:'#include <iostream>\nusing namespace std;\nint main() {\n    int n;\n    cin >> n;\n    cout << n << endl;\n    return 0;\n}',
  java:'import java.util.Scanner;\npublic class Main {\n    public static void main(String[] args) {\n        Scanner sc = new Scanner(System.in);\n        int n = sc.nextInt();\n        System.out.println(n);\n    }\n}',
  c:'#include <stdio.h>\nint main() {\n    int n;\n    scanf("%d", &n);\n    printf("%d\\n", n);\n    return 0;\n}',
  go:'package main\nimport "fmt"\nfunc main() {\n    var n int\n    fmt.Scan(&n)\n    fmt.Println(n)\n}',
  rust:'use std::io;\nfn main() {\n    let mut s = String::new();\n    io::stdin().read_line(&mut s).unwrap();\n    println!("{}", s.trim());\n}',
  typescript:'function solve(): void {\n  // your code\n}\nsolve();',
  ruby:'n = gets.to_i\nputs n',
};

export default function WorkspacePage() {
  const [projects,setProjects]=useState([]);const [proj,setProj]=useState(null);
  const [chats,setChats]=useState([]);const [chat,setChat]=useState(null);
  const [lang,setLang]=useState('python');const [code,setCode]=useState(STARTERS.python);
  const [problem,setProblem]=useState('');const [approach,setApproach]=useState('');
  const [edges,setEdges]=useState('');const [complexity,setComplexity]=useState('');
  const [stdin,setStdin]=useState('');const [showStdin,setShowStdin]=useState(false);
  const [showThink,setShowThink]=useState(true);
  const [result,setResult]=useState(null);const [analyzing,setAnalyzing]=useState(false);const [running,setRunning]=useState(false);

  useEffect(()=>{api.get('/projects').then(r=>setProjects(r.data)).catch(()=>{});},[]);
  useEffect(()=>{if(proj)api.get(`/projects/${proj._id}/chats`).then(r=>setChats(r.data)).catch(()=>{});else setChats([]);},[proj]);

  const newProj=async name=>{try{const{data}=await api.post('/projects',{name,language:lang});setProjects(p=>[data,...p]);setProj(data);setChat(null);setResult(null);}catch{}};
  const newChat=async()=>{if(!proj)return;try{const{data}=await api.post(`/projects/${proj._id}/chats`,{title:problem||'New Analysis'});setChats(p=>[data,...p]);setChat(data);setResult(null);setCode(STARTERS[lang]||'');}catch{}};
  const selChat=async c=>{setChat(c);try{const{data}=await api.get(`/analysis/chat/${c._id}`);if(data.entries?.length){const l=data.entries[data.entries.length-1];setCode(l.code||'');setLang(l.language||'python');setProblem(l.problemStatement||'');setApproach(l.preCodingThinking?.approach||'');setEdges(l.preCodingThinking?.edgeCases||'');setComplexity(l.preCodingThinking?.expectedComplexity||'');setResult({executionResult:l.executionResult,staticAnalysis:l.staticAnalysis?.issues,testCases:l.testCases,whyAnalysis:l.whyAnalysis,deltaAnalysis:l.deltaAnalysis,attemptNumber:l.attemptNumber,pipelineSteps:l.pipelineSteps,processingTime:l.processingTime});}}catch{}};

  const run=async()=>{if(!code.trim())return;setRunning(true);try{const{data}=await api.post('/code/run',{code,language:lang});setResult(p=>({...p,executionResult:data}));}catch(e){setResult(p=>({...p,executionResult:{stderr:e.response?.data?.error||e.message,status:'Error'}}));}finally{setRunning(false);}};

  const analyze=async()=>{if(!code.trim())return;if(!proj){alert('Create a project first');return;}setAnalyzing(true);try{const{data}=await api.post('/code/analyze',{code,language:lang,problemStatement:problem,preCodingThinking:{approach,edgeCases:edges,expectedComplexity:complexity},chatId:chat?._id,projectId:proj._id});setResult(data);if(data.chatId&&!chat){const nc={_id:data.chatId,title:(problem||'Analysis').slice(0,60)};setChat(nc);setChats(p=>[nc,...p]);}}catch(e){setResult({executionResult:{stderr:e.response?.data?.error||e.message,status:'Error'},pipelineSteps:e.response?.data?.pipelineSteps});}finally{setAnalyzing(false);}};

  const chLang=v=>{setLang(v);if(!code||Object.values(STARTERS).some(s=>code.trim()===s.trim()))setCode(STARTERS[v]||'');};

  return(
    <div className="app">
      <Sidebar projects={projects} chats={chats} activeProject={proj} activeChat={chat}
        onSelectProject={p=>{setProj(p);setChat(null);setResult(null);}} onSelectChat={selChat}
        onNewProject={newProj} onNewChat={newChat}/>
      <div className="main">
        <div className="top"><div className="top-t">{proj?<><b>{proj.name}</b>{chat?` › ${chat.title}`:''}</>:'Select or create a project'}</div>
          <div className="top-a">
            <button className="btn btn-g btn-sm" onClick={()=>setShowThink(t=>!t)}>{showThink?'▲ Hide':'▼ Show'} Thinking</button>
            <button className="btn btn-s btn-sm" onClick={run} disabled={running||!code.trim()}>{running?<><div className="spinner"/>Running</>:'▶ Run'}</button>
            <button className="btn btn-p btn-sm" onClick={analyze} disabled={analyzing||!code.trim()}>{analyzing?<><div className="spinner"/>Analyzing</>:'🧠 Analyze'}</button>
          </div>
        </div>
        <div className="ws">
          <div className="ws-ed">
            {showThink&&<div className="think">
              <label>Problem Statement</label>
              <textarea value={problem} onChange={e=>setProblem(e.target.value)} placeholder="What problem are you solving?" rows={2}/>
              <div className="think-g">
                <div><label>Your Approach</label><input value={approach} onChange={e=>setApproach(e.target.value)} placeholder="How will you solve it?"/></div>
                <div><label>Edge Cases</label><input value={edges} onChange={e=>setEdges(e.target.value)} placeholder="What could go wrong?"/></div>
                <div><label>Expected Complexity</label><input value={complexity} onChange={e=>setComplexity(e.target.value)} placeholder="O(n), O(n²)..."/></div>
              </div>
            </div>}
            <div className="ed-bar">
              <select className="lang-sel" value={lang} onChange={e=>chLang(e.target.value)}>{LANGS.map(l=><option key={l.v} value={l.v}>{l.l}</option>)}</select>
              <span className="att">Attempt #{result?.attemptNumber||1}</span>
            </div>
            <div style={{flex:1}}>
              <Editor height="100%" language={lang==='cpp'?'cpp':lang} value={code} onChange={v=>setCode(v||'')} theme="vs-dark"
                options={{fontSize:14,fontFamily:"'JetBrains Mono',monospace",minimap:{enabled:false},padding:{top:12,bottom:12},scrollBeyondLastLine:false,wordWrap:'on',lineNumbers:'on',smoothScrolling:true,cursorBlinking:'smooth',bracketPairColorization:{enabled:true}}}/>
            </div>
          </div>
          <AnalysisPanel result={result} loading={analyzing}/>
        </div>
      </div>
    </div>
  );
}
